sqlMap.select:
SELECT COUNT(*) FROM TBL_WEBFOLDER_SHARE WHERE ((FOLDERFILE_TYPE = 'D' AND FOLDERFILE_ID = #folderId#) OR (FOLDERFILE_TYPE = 'D' AND SUB_STATUS = 'Y'
#parentIdList[]#
)
OR (FOLDERFILE_TYPE = 'F' AND FOLDERFILE_ID = #fileId#)
) AND TENANT_ID = #tenantId#

SELECT * FROM ( SELECT DISTINCT FAVOR.TARGET_ID, FILES.FILE_NAME AS TARGET_NAME, FAVOR.TARGET_TYPE AS TARGET_TYPE, FILE_TYPE.TYPE_ICON AS TARGET_ICON_URL, FILE_TYPE.TYPE_NAME, FOLDER.FOLDER_PATH AS TARGET_PATH, FILES.FILE_EXT AS TARGET_EXT, FILES.FILE_SIZE AS TARGET_SIZE, FILES.CREATE_ID, FILES.CREATE_NAME1, FILES.CREATE_NAME2, DATE_ADD(FAVOR.CREATE_DATE, INTERVAL #offset# MINUTE) AS CREATE_DATE, FAVOR.TENANT_ID FROM TBL_WEBFOLDER_FAVOR AS FAVOR INNER JOIN TBL_WEBFOLDER_FILE AS FILES ON FILES.FILE_ID = FAVOR.TARGET_ID AND FILES.TENANT_ID = FAVOR.TENANT_ID INNER JOIN TBL_WEBFOLDER_FOLDER FOLDER ON FOLDER.FOLDER_ID = FILES.FOLDER_ID INNER JOIN TBL_WEBFOLDER_FILETYPE as FILE_TYPE ON FILE_TYPE.TYPE_ID = FILES.TYPE_ID WHERE FAVOR.TARGET_TYPE = 'F' AND FAVOR.USER_ID = #userId# AND FAVOR.TENANT_ID = #tenantId# AND FILES.USE_STATUS = 'Y'
UNION
SELECT DISTINCT FAVOR.TARGET_ID, FOLDER.FOLDER_NAME1 AS TARGET_NAME, CONCAT('D_', FOLDER.FOLDER_TYPE) AS TARGET_TYPE, FILE_TYPE.TYPE_ICON AS TARGET_ICON_URL, FILE_TYPE.TYPE_NAME, FOLDER.FOLDER_PATH AS TARGET_PATH, 'folder' AS TARGET_EXT, 0 AS TARGET_SIZE, FOLDER.CREATE_ID, FOLDER.CREATE_NAME1, FOLDER.CREATE_NAME2, DATE_ADD(FAVOR.CREATE_DATE, INTERVAL #offset# MINUTE) AS CREATE_DATE, FAVOR.TENANT_ID FROM TBL_WEBFOLDER_FAVOR AS FAVOR INNER JOIN TBL_WEBFOLDER_FILETYPE AS FILE_TYPE ON FILE_TYPE.TYPE_NAME = 'folder' INNER JOIN TBL_WEBFOLDER_FOLDER AS FOLDER ON FOLDER.FOLDER_ID = FAVOR.TARGET_ID AND FOLDER.TENANT_ID = FAVOR.TENANT_ID WHERE FAVOR.TARGET_TYPE = 'D' AND FAVOR.USER_ID = #userId# AND FAVOR.TENANT_ID = #tenantId# AND FOLDER.USE_STATUS = 'Y' ) AS RESULT WHERE RESULT.TARGET_EXT LIKE CONCAT('%', #searchExt#, '%') AND RESULT.TARGET_NAME LIKE CONCAT('%', #searchFileName#, '%') AND RESULT.CREATE_NAME1 LIKE CONCAT('%', #searchCreatorName#, '%') AND RESULT.TARGET_TYPE LIKE CONCAT('%', #searchFileType#, '%') ORDER BY RESULT.TARGET_TYPE ASC, CREATE_DATE DESC LIMIT #startIndex#, #endIndex#;
